import React, { useState, useEffect } from "react";
import { obtenerUsuarios, ascenderUsuario, degradarUsuario } from "../services/UserService";
import styles from "../styles/CategoryManager.module.css";

const UserManager = () => {
  const [usuarios, setUsuarios] = useState([]);
  const [error, setError] = useState("");
  const [cargando, setCargando] = useState(true);
  const usuarioActual = JSON.parse(localStorage.getItem("loggedUser"));

  useEffect(() => {
    cargarUsuarios();
  }, []);

  const cargarUsuarios = async () => {
    try {
      const data = await obtenerUsuarios();
      setUsuarios(data);
    } catch (err) {
      setError("Error al cargar usuarios.");
    } finally {
      setCargando(false);
    }
  };

  const manejarAscenso = async (id) => {
    if (!window.confirm("¿Seguro que quieres ascender a este usuario a GESTOR?")) return;
    try {
      await ascenderUsuario(id);
      cargarUsuarios();
    } catch (err) {
      setError("Error al ascender usuario.");
    }
  };

  const manejarDegradacion = async (id) => {
    if (!window.confirm("¿Seguro que quieres degradar a este usuario a USER?")) return;
    try {
      await degradarUsuario(id);
      cargarUsuarios();
    } catch (err) {
      setError("Error al degradar usuario.");
    }
  };

  return (
    <div className={styles.managerCard}>
      <h3 className={styles.title}>Gestión de Usuarios (Admin)</h3>
      {error && <div style={{ color: "red", marginBottom: "10px" }}>{error}</div>}

      {cargando ? (
        <p>Cargando usuarios...</p>
      ) : (
        <ul className={styles.list}>
          {usuarios.map((user) => (
            <li key={user.id} className={styles.listItem}>
              <div>
                <strong>{user.nombreUsuario}</strong>
                <span style={{ marginLeft: "10px", fontSize: "0.8em", color: "#888" }}>
                  ({user.rol})
                </span>
              </div>

              <div style={{ display: "flex", gap: "10px" }}>
                {user.rol === "USER" && (
                  <button 
                    onClick={() => manejarAscenso(user.id)} 
                    style={{ background: "#4caf50", border: "none", color: "white", padding: "5px 10px", borderRadius: "5px", cursor: "pointer" }}
                  >
                    Ascender
                  </button>
                )}
                {user.rol === "GESTOR" && (
                  <button 
                    onClick={() => manejarDegradacion(user.id)} 
                    style={{ background: "#ff9800", border: "none", color: "white", padding: "5px 10px", borderRadius: "5px", cursor: "pointer" }}
                  >
                    Degradar
                  </button>
                )}
                {user.id === usuarioActual?.id && (
                  <span style={{ fontSize: "0.8em", color: "#4caf50" }}>Tú</span>
                )}
              </div>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
};

export default UserManager;
